const dossier = $input.item.json;
const pj = $node['Receive from W1'].json.pieces_jointes || [];

// Build content array for Claude Vision
const content = [];

// Add each attachment as image
for (const attachment of pj) {
  if (attachment.base64) {
    const mediaType = attachment.type || 'image/jpeg';
    content.push({
      type: 'image',
      source: {
        type: 'base64',
        media_type: mediaType.includes('pdf') ? 'image/png' : mediaType,
        data: attachment.base64
      }
    });
  }
}

// Add the analysis prompt
const prompt = `Analyse le document ci-joint pour le dossier de remboursement.

CONTEXTE DU DOSSIER :
- Reference : ${dossier.ref_dossier || dossier.id}
- Assure : ${dossier.nom_assure || ''}
- Motif declare : ${dossier.motif_declare || ''} — ${dossier.motif_detail || ''}
- Evenement sportif : ${dossier.nom_evenement || ''}
- Date evenement : ${dossier.date_evenement || ''}
- Date souscription : ${dossier.date_souscription || ''}
- Date annulation : ${dossier.date_annulation || ''}

Analyse le document joint et reponds en JSON valide.`;

content.push({ type: 'text', text: prompt });

return {
  json: {
    dossier_id: dossier.id,
    claude_body: {
      model: 'claude-sonnet-4-20250514',
      max_tokens: 1024,
      system: `Tu es un agent expert en analyse documentaire pour Assur Connect, courtier en assurance annulation de dossards sportifs.\n\nMISSION : Analyser le document joint et en extraire les informations structurees.\n\nTYPES DE DOCUMENTS : certificat medical, attestation employeur, convocation officielle, justificatif familial, resultat d'examen.\n\nINSTRUCTIONS :\n- Extrais UNIQUEMENT les informations visibles. N'invente rien.\n- Signale tout signe de modification ou d'anomalie.\n- Evalue la coherence et le lien avec l'impossibilite sportive.\n\nREPONSE : JSON valide uniquement avec les champs : type_document, date_document, emetteur {nom, qualite, coordonnees_presentes}, motif_extrait, diagnostic, dates_indisponibilite {debut, fin}, coherence_apparente, raison_incoherence, signes_modification, detail_modification, qualite_document, informations_manquantes, lien_sport, notes.`,
      messages: [{ role: 'user', content: content }]
    }
  }
};

const response = $input.item.json;
const dossier_id = $node['Prepare Claude Vision Request'].json.dossier_id;

let analysis = null;
try {
  const text = response.content?.[0]?.text || '';
  // Extract JSON from response (handle markdown code blocks)
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  analysis = {
    type_document: 'inconnu',
    qualite_document: 'illisible',
    coherence_apparente: 'incertain',
    notes: 'Erreur parsing reponse Claude: ' + e.message
  };
}

return {
  json: {
    dossier_id: dossier_id,
    document_analysis: analysis,
    status: 'analyse'
  }
};

return {
  json: {
    dossier_id: $input.item.json.id,
    document_analysis: null,
    status: 'analyse'
  }
};
